// Build Apollo search parameters dynamically per business
const webhookData = $input.first().json;
const isWebhook = !!(webhookData.body && (webhookData.body.regions || webhookData.body.queries || webhookData.body.audience_type));

// Fetch businesses from upstream node
let businesses = [];
try {
  const bizItems = $('Fetch All Businesses').all().map(i => i.json);
  businesses = Array.isArray(bizItems[0]) ? bizItems[0] : bizItems;
} catch(e) {
  businesses = [];
}

// Category to Apollo industry tag mapping
const categoryToIndustry = {
  'auto_repair': { tags: ['auto_repair'], titles: ['owner', 'manager', 'general manager', 'service manager', 'shop owner'] },
  'salon': { tags: ['beauty_salon', 'hair_salon'], titles: ['owner', 'manager', 'salon owner', 'studio owner'] },
  'hvac': { tags: ['hvac'], titles: ['owner', 'manager', 'general manager', 'service manager'] },
  'plumbing': { tags: ['plumbing'], titles: ['owner', 'manager', 'general manager'] },
  'dental': { tags: ['dental_practice'], titles: ['owner', 'practice manager', 'office manager', 'dentist'] },
  'fitness': { tags: ['fitness', 'gym'], titles: ['owner', 'manager', 'gym owner', 'studio owner'] },
  'restaurant': { tags: ['restaurant', 'food_service'], titles: ['owner', 'manager', 'general manager'] },
  'cleaning': { tags: ['cleaning_service', 'janitorial'], titles: ['owner', 'manager', 'operations manager'] },
  'landscaping': { tags: ['landscaping'], titles: ['owner', 'manager', 'operations manager'] },
  'pet_care': { tags: ['veterinary', 'pet_care'], titles: ['owner', 'manager', 'practice manager'] }
};

let employeeRanges = ['1,10', '11,20', '21,50'];
let locations = ['United States'];
let perPage = 100;

// If webhook override, use those params
if (isWebhook) {
  const body = webhookData.body;
  if (body.regions && body.regions.length > 0) {
    locations = body.regions.map(r => r + ', United States');
  }

  // If webhook specifies audience_type, just run that one
  if (body.audience_type) {
    const config = categoryToIndustry[body.audience_type] || { tags: [body.audience_type], titles: ['owner', 'manager'] };
    let titles = config.titles;
    if (body.queries && body.queries.length > 0) {
      titles = [...new Set([...titles, ...body.queries])];
    }
    return [{
      json: {
        businessId: body.business_id || 'webhook',
        industryTags: config.tags,
        employeeRanges,
        locations,
        personTitles: titles,
        perPage,
        currentPage: 1,
        isWebhook: true
      }
    }];
  }
}

// Track pagination via static data
const staticData = $getWorkflowStaticData('global');
const today = $now.toFormat('yyyy-MM-dd');
if (!staticData.pagePerBusiness) staticData.pagePerBusiness = {};
if (staticData.lastRunDate !== today) {
  staticData.pagePerBusiness = {};
  staticData.lastRunDate = today;
}

// Generate one search config per active business
const searchConfigs = [];
for (const biz of businesses) {
  const category = biz.category || 'auto_repair';
  const config = categoryToIndustry[category] || { tags: [category], titles: ['owner', 'manager'] };

  const bizKey = biz.business_id || biz.id;
  if (!staticData.pagePerBusiness[bizKey]) staticData.pagePerBusiness[bizKey] = 1;

  searchConfigs.push({
    json: {
      businessId: biz.business_id,
      businessUuid: biz.id,
      businessName: biz.name,
      category: category,
      industryTags: config.tags,
      employeeRanges,
      locations,
      personTitles: config.titles,
      perPage,
      currentPage: staticData.pagePerBusiness[bizKey],
      isWebhook: false
    }
  });
}

if (searchConfigs.length === 0) {
  // Fallback to auto_repair if no businesses found
  return [{
    json: {
      businessId: 'unknown',
      industryTags: ['auto_repair'],
      employeeRanges,
      locations,
      personTitles: ['owner', 'manager', 'general manager', 'service manager', 'shop owner'],
      perPage,
      currentPage: 1,
      isWebhook: false
    }
  }];
}

return searchConfigs;

const response = $input.first().json;
const searchParams = $('Build Apollo Search Params (Per Business)').item.json;

const staticData = $getWorkflowStaticData('global');
const organizations = response.organizations || response.accounts || [];

if (!organizations || organizations.length === 0) {
  const bizKey = searchParams.businessId || 'unknown';
  if (staticData.pagePerBusiness) staticData.pagePerBusiness[bizKey] = 1;
  return [{ json: { _empty: true, reason: 'No organizations found for ' + searchParams.businessId + ' (' + (searchParams.industryTags || []).join(',') + '). Page: ' + searchParams.currentPage, totalProcessed: 0 } }];
}

// Advance page for next batch
const bizKey = searchParams.businessId || 'unknown';
if (staticData.pagePerBusiness) {
  staticData.pagePerBusiness[bizKey] = (staticData.pagePerBusiness[bizKey] || 1) + 1;
}

return organizations.map(org => ({
  json: {
    org_id: org.id || org.organization_id || '',
    business_name: org.name || '',
    website: org.website_url || org.primary_domain || '',
    domain: (org.primary_domain || org.website_url || '').replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0],
    phone: org.phone || org.sanitized_phone || '',
    industry: org.industry || '',
    company_size: org.estimated_num_employees ? String(org.estimated_num_employees) : (org.num_employees_ranges ? org.num_employees_ranges[0] : ''),
    annual_revenue: org.annual_revenue_printed || org.annual_revenue || '',
    city: org.city || '',
    state: org.state || '',
    country: org.country || 'United States',
    technologies: org.technologies || [],
    linkedin_url: org.linkedin_url || '',
    apollo_org_id: org.id || org.organization_id || '',
    personTitles: searchParams.personTitles,
    _forBusinessId: searchParams.businessId,
    _forBusinessUuid: searchParams.businessUuid
  }
}));

const response = $input.first().json;
const orgData = $('Has Organizations?').first().json;
const people = response.people || response.contacts || [];

if (!people || people.length === 0) {
  return [{ json: { _empty: true, reason: 'No decision makers found for ' + orgData.business_name, org_id: orgData.org_id } }];
}

const best = people[0];
return [{
  json: {
    apollo_id: best.id || '',
    first_name: best.first_name || '',
    last_name: best.last_name || '',
    title: best.title || '',
    seniority: best.seniority || '',
    email: best.email || '',
    phone: best.phone_numbers ? (best.phone_numbers[0] || {}).sanitized_number || '' : (orgData.phone || ''),
    linkedin_url: best.linkedin_url || orgData.linkedin_url || '',
    person_city: best.city || '',
    person_state: best.state || '',
    business_name: orgData.business_name,
    website: orgData.website,
    domain: orgData.domain,
    industry: orgData.industry,
    company_size: orgData.company_size,
    annual_revenue: orgData.annual_revenue,
    city: orgData.city || best.city || '',
    state: orgData.state || best.state || '',
    technologies: orgData.technologies,
    apollo_org_id: orgData.apollo_org_id,
    _forBusinessId: orgData._forBusinessId,
    _forBusinessUuid: orgData._forBusinessUuid
  }
}];

const enriched = $input.first().json;
const prevData = $('Found Decision Maker?').first().json;
const person = enriched.person || enriched;

let email = '';
if (person.email) email = person.email;
else if (person.personal_emails && person.personal_emails.length > 0) email = person.personal_emails[0];
else if (prevData.email) email = prevData.email;

let phone = prevData.phone || '';
if (person.phone_numbers && person.phone_numbers.length > 0) phone = person.phone_numbers[0].sanitized_number || person.phone_numbers[0].number || phone;
else if (person.phone) phone = person.phone;

if (!email) {
  return [{ json: { _skip: true, reason: 'No email found after enrichment', business_name: prevData.business_name, apollo_id: prevData.apollo_id } }];
}

return [{ json: { ...prevData, email, phone, linkedin_url: person.linkedin_url || prevData.linkedin_url || '', title: person.title || prevData.title || '', seniority: person.seniority || prevData.seniority || '' } }];

const dupeCheck = $input.first().json;
const leadData = $('Has Email?').first().json;
const results = Array.isArray(dupeCheck) ? dupeCheck : [];
if (results.length > 0) {
  return [{ json: { _skip: true, reason: 'Duplicate', email: leadData.email, business_name: leadData.business_name } }];
}
return [{ json: { ...leadData, _skip: false } }];

const verifyResponse = $input.first().json;
const leadData = $('Not Duplicate?').first().json;
const result = (verifyResponse.result || '').toLowerCase();
const acceptable = ['ok', 'catch_all'];
if (!acceptable.includes(result)) {
  return [{ json: { _skip: true, reason: 'Email validation failed: ' + result, email: leadData.email, business_name: leadData.business_name } }];
}
return [{ json: { ...leadData, email_verified: true, email_verify_result: result } }];

const allSaved = $input.all();
const dateStr = $now.toFormat('yyyy-MM-dd');
let savedCount = 0, failedCount = 0;
const statesSeen = new Set();
const savedLeads = [];
const businessesSeen = new Set();

for (const item of allSaved) {
  const d = item.json;
  if (d.id || (Array.isArray(d) && d.length > 0)) {
    savedCount++;
    const lead = Array.isArray(d) ? d[0] : d;
    if (lead.state) statesSeen.add(lead.state);
    if (lead.business_id) businessesSeen.add(lead.business_id);
    savedLeads.push({ business: lead.business_name || 'Unknown', email: lead.email || 'N/A', title: lead.title || 'N/A', city: lead.city || 'N/A', state: lead.state || 'N/A' });
  } else {
    failedCount++;
  }
}

let report = '# Apollo Lead Gen Report - ' + dateStr + '\n\n';
report += '## Summary\n';
report += '- **Date**: ' + new Date().toISOString() + '\n';
report += '- **New validated leads saved**: ' + savedCount + '\n';
report += '- **Failed/skipped**: ' + failedCount + '\n';
report += '- **States covered**: ' + Array.from(statesSeen).join(', ') + '\n';
report += '- **Businesses served**: ' + Array.from(businessesSeen).join(', ') + '\n\n';

if (savedLeads.length > 0) {
  report += '## New Leads\n\n';
  report += '| Business | Email | Title | City | State |\n';
  report += '|----------|-------|-------|------|-------|\n';
  for (const lead of savedLeads) {
    report += '| ' + lead.business + ' | ' + lead.email + ' | ' + lead.title + ' | ' + lead.city + ' | ' + lead.state + ' |\n';
  }
}

return [{ json: { report, dateStr, savedCount, failedCount, telegramMessage: 'Apollo Lead Gen: Found ' + savedCount + ' new validated leads across ' + businessesSeen.size + ' businesses. States: ' + Array.from(statesSeen).join(', ') + '. Failed/skipped: ' + failedCount + '.' } }];
